const T={brazil:{tmin:26,tmax:32,hmin:53,hmax:57},ecuador:{tmin:28,tmax:34,hmin:58,hmax:62},colombia:{tmin:23,tmax:29,hmin:78,hmax:82}};
const parts=(msg.topic||'').split('/');
const country=parts[1];
const cfg=T[country];
if(!cfg){return null;}
const p=msg.payload||{};
const temp=Number(p.temperature);
const hum=Number(p.humidity);
const wid=p.warehouseId||parts[2]||'?';
if(isNaN(temp)||isNaN(hum)){return null;}
const problems=[];
if(temp<cfg.tmin||temp>cfg.tmax){problems.push('température '+temp+'°C hors plage ['+cfg.tmin+'-'+cfg.tmax+'°C]');}
if(hum<cfg.hmin||hum>cfg.hmax){problems.push('humidité '+hum+'% hors plage ['+cfg.hmin+'-'+cfg.hmax+'%]');}
if(problems.length===0){node.status({fill:'green',shape:'dot',text:wid+' OK'});return null;}
node.status({fill:'red',shape:'ring',text:'anomalie '+wid});
msg.country=country;
msg.warehouse=wid;
msg.subject='[Node-RED][FutureKawa '+country+'] Anomalie entrepôt '+wid;
msg.body='Anomalie détectée sur '+wid+' ('+country+') :\n- '+problems.join('\n- ')+'\nMesure: '+temp+'°C / '+hum+'%';
return msg;

const host=env.get('SMTP_HOST');
if(!host){
  node.warn('SMTP non configuré -> email simulé: '+msg.subject);
  return [null,{topic:msg.subject,payload:msg.body}];
}
msg.to=env.get('SMTP_TO')||env.get('SMTP_FROM')||'responsable@futurekawa.com';
msg.from=env.get('SMTP_FROM')||'node-red@futurekawa.com';
msg.topic=msg.subject;
msg.payload=msg.body;
return [msg,null];
